parameters.jsCode:
const fields = $input.first().json.body.data.fields;

const resolved = {};

for (const field of fields) {
  const key = field.label.trim();

  if (field.value === null || field.value === undefined) {
    resolved[key] = null;
    continue;
  }

  // Dropdown fields — resolve UUID(s) to text
  if (field.type === "DROPDOWN" || field.type === "MULTIPLE_CHOICE") {
    const selectedIds = Array.isArray(field.value) ? field.value : [field.value];
    const selectedTexts = selectedIds.map(id => {
      const match = field.options.find(opt => opt.id === id);
      return match ? match.text : id;
    });
    resolved[key] = selectedTexts.length === 1 ? selectedTexts[0] : selectedTexts;
  } else {
    // Plain fields — text, email, textarea
    resolved[key] = Array.isArray(field.value) ? field.value[0] : field.value;
  }
}

return [{ json: resolved }];

